/**
 * DOMPurify - Minimal vendored HTML sanitizer for the registry SPA.
 *
 * Strips <script> tags, on* event handlers, javascript: URIs, and
 * dangerous elements (iframe, object, embed, form).
 *
 * Replace with the full DOMPurify library for production use:
 *   https://cdn.jsdelivr.net/npm/dompurify/dist/purify.min.js
 */
(function (global) {
    'use strict';

    // Dangerous tags to remove entirely (including content)
    var REMOVE_TAGS_RE = /<(script|iframe|object|embed|form|style)\b[^>]*>[\s\S]*?<\/\1>/gi;
    // Self-closing dangerous tags
    var REMOVE_SELF_CLOSING_RE = /<(script|iframe|object|embed|form|style)\b[^>]*\/?>/gi;
    // Event handler attributes: on*="..."
    var EVENT_HANDLER_RE = /\s+on\w+\s*=\s*("[^"]*"|'[^']*'|[^\s>]+)/gi;
    // javascript: URIs in href/src/action attributes
    var JS_URI_RE = /(href|src|action)\s*=\s*["']?\s*javascript\s*:/gi;

    function sanitize(dirty) {
        if (!dirty) return '';
        var clean = String(dirty);
        // Remove dangerous tags with content
        clean = clean.replace(REMOVE_TAGS_RE, '');
        // Remove self-closing dangerous tags
        clean = clean.replace(REMOVE_SELF_CLOSING_RE, '');
        // Remove event handlers
        clean = clean.replace(EVENT_HANDLER_RE, '');
        // Neutralize javascript: URIs
        clean = clean.replace(JS_URI_RE, '$1="about:blank"');
        return clean;
    }

    var DOMPurify = {
        sanitize: sanitize,
    };

    if (typeof module !== 'undefined' && module.exports) {
        module.exports = DOMPurify;
    } else {
        global.DOMPurify = DOMPurify;
    }
})(typeof globalThis !== 'undefined' ? globalThis : typeof window !== 'undefined' ? window : this);
